1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	export function nextGeneration(liveCells: Cell[]): Cell[] {
15	  const liveKeys = new Set(liveCells.map(keyOf));
16	  const neighborhood = new Map<string, { cell: Cell; count: number }>();
17	
18	  for (const cell of liveCells.flatMap(neighborsOf)) {
19	    const k = keyOf(cell);
20	    const prev = neighborhood.get(k);
21	    neighborhood.set(k, { cell, count: (prev?.count ?? 0) + 1 });
22	  }
23	
24	  const survives = (k: string, count: number): boolean =>
25	    count === 3 || (count === 2 && liveKeys.has(k));
26	
27	  return Array.from(neighborhood)
28	    .filter(([k, { count }]) => survives(k, count))
29	    .map(([, { cell }]) => cell);
30	}
