1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) unchanged (still life)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should transform a vertical blinker to horizontal (oscillator)", () => {
20	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
21	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect(result.sort()).toEqual(expected.sort());
24	  });
25	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
26	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
27	    const result = nextGeneration(input);
28	    expect(result).toContainEqual([1, 1]);
29	  });
30	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
31	    const input: [number, number][] = [
32	      [0, 0], [1, 0], [2, 0],
33	      [1, 1],
34	      [0, 2], [1, 2], [2, 2],
35	    ];
36	    const result = nextGeneration(input);
37	    expect(result).not.toContainEqual([1, 1]);
38	  });
39	  it("should handle negative coordinates", () => {
40	    const negBlock: [number, number][] = [[-2, -2], [-1, -2], [-2, -1], [-1, -1]];
41	    const result = nextGeneration(negBlock);
42	    expect(result.sort()).toEqual(negBlock.sort());
43	  });
44	});
