export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(keyOf));
  const candidates = new Map<string, Cell>(
    liveCells.flatMap(neighborsOf).map((cell) => [keyOf(cell), cell]),
  );

  const neighborCount = (key: string): number =>
    NEIGHBOR_OFFSETS.reduce((count, [dx, dy]) => {
      const [x, y] = candidates.get(key)!;
      return count + (liveKeys.has(keyOf([x + dx, y + dy])) ? 1 : 0);
    }, 0);

  const survives = (key: string): boolean => {
    const count = neighborCount(key);
    return count === 3 || (count === 2 && liveKeys.has(key));
  };

  return Array.from(candidates)
    .filter(([key]) => survives(key))
    .map(([, cell]) => cell);
}

