const survives = (count: number, wasAlive: boolean): boolean =>
  count === 3 || (count === 2 && wasAlive);

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(keyOf));
  const counts = liveCells
    .flatMap(neighborsOf)
    .reduce((acc, cell) => {
      const k = keyOf(cell);
      const entry = acc.get(k) ?? { cell, count: 0 };
      entry.count += 1;
      acc.set(k, entry);
      return acc;
    }, new Map<string, { cell: Cell; count: number }>());

  return Array.from(counts.values())
    .filter(({ cell, count }) => survives(count, liveKeys.has(keyOf(cell))))
    .map(({ cell }) => cell);
}

