  const counts = candidates.reduce(
    (acc, cell) => acc.set(keyOf(cell), (acc.get(keyOf(cell)) ?? 0) + 1),
    new Map<string, number>(),
  );

  const uniqueCandidates = new Map(candidates.map((cell) => [keyOf(cell), cell]));
